import { NextRequest, NextResponse } from "next/server"
import { getRequestContext } from "@cloudflare/next-on-pages"

export const dynamic = 'error'

// Dostępne modele Workers AI
const MODELS = {
  chat: "@cf/meta/llama-3.3-70b-instruct-fp8-fast",
  vision: "@cf/llava-hf/llava-1.5-7b-hf",
  embedding: "@cf/baai/bge-base-en-v1.5",
} as const

export async function POST(req: NextRequest) {
  try {
    const body = await req.json() as { action?: string; prompt?: string; messages?: { role: string; content: string }[]; model?: string; title?: string; style?: string }
    const { action, prompt, messages, model } = body

    let env: CloudflareEnv
    try {
      env = getRequestContext().env as CloudflareEnv
    } catch {
      // Lokalnie (bez CF) — zwróć mock
      return NextResponse.json({
        result: `[LOCAL] AI Workers niedostępne lokalnie. Odpowiedź na: "${prompt || messages?.at(-1)?.content}"`,
      })
    }

    const ai = env.AI

    switch (action) {
      // ── Chat / asystent filmowy / muzyczny ──────────────────────────────
      case "chat": {
        const msgs = messages ?? [{ role: "user", content: prompt ?? "" }]
        const result = await ai.run((model ?? MODELS.chat) as typeof MODELS.chat, {
          messages: [
            {
              role: "system",
              content:
                "Jesteś BONZO AI — asystentem aplikacji multimedialnej BONZO_media_HUB. Specjalizujesz się w filmach, muzyce i rekomendacjach. Odpowiadaj po polsku, zwięźle i z charakterem.",
            },
            ...msgs,
          ],
          max_tokens: 1024,
        })
        return NextResponse.json({ result: (result as { response: string }).response })
      }

      // ── Rekomendacje filmowe ─────────────────────────────────────────────
      case "film_recommend": {
        const result = await ai.run(MODELS.chat, {
          messages: [
            {
              role: "system",
              content:
                "Jesteś ekspertem filmowym. Na podstawie podanego gatunku/nastroju podaj 5 rekomendacji filmów z krótkim uzasadnieniem. Format: JSON array [{title, year, reason}]",
            },
            { role: "user", content: prompt ?? "" },
          ],
          max_tokens: 512,
        })
        let recommendations
        try {
          const text = (result as { response: string }).response
          const jsonMatch = text.match(/\[[\s\S]*\]/)
          recommendations = jsonMatch ? JSON.parse(jsonMatch[0]) : text
        } catch {
          recommendations = (result as { response: string }).response
        }
        return NextResponse.json({ result: recommendations })
      }

      // ── Opis / recenzja na żądanie ───────────────────────────────────────
      case "review": {
        const { title, style = "kinoman" } = body
        const styles: Record<string, string> = {
          kinoman: "Napisz wnikliwą recenzję filmową w stylu doświadczonego kinomana.",
          gigachad: "Napisz recenzję w stylu GIGACHAD — bezpośrednio, z humorem i pewnością siebie.",
          academic: "Napisz akademicką analizę filmu z użyciem terminologii filmoznawczej.",
        }
        const result = await ai.run(MODELS.chat, {
          messages: [
            { role: "system", content: styles[style] ?? styles.kinoman },
            { role: "user", content: `Film: ${title ?? prompt}` },
          ],
          max_tokens: 800,
        })
        return NextResponse.json({ result: (result as { response: string }).response })
      }

      // ── Embedding (semantic search) ──────────────────────────────────────
      case "embed": {
        const result = await ai.run(MODELS.embedding, { text: [prompt ?? ""] })
        return NextResponse.json({ result: (result as { data: number[][] }).data[0] })
      }

      default:
        return NextResponse.json({ error: "Nieznana akcja" }, { status: 400 })
    }
  } catch (err) {
    console.error("AI route error:", err)
    return NextResponse.json({ error: "Błąd AI" }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'

export const dynamic = 'error'

// Proxy dla DeepSeek API — klucz zostaje po stronie serwera
export async function POST(request: NextRequest) {
  const apiKey = process.env.DEEPSEEK_API_KEY
  if (!apiKey) {
    return NextResponse.json(
      { error: 'Brak klucza DEEPSEEK_API_KEY w .env. Dodaj: DEEPSEEK_API_KEY=sk-...' },
      { status: 500 }
    )
  }

  let body: { messages: { role: string; content: string }[] }
  try {
    body = await request.json()
  } catch {
    return NextResponse.json({ error: 'Nieprawidłowy JSON' }, { status: 400 })
  }

  if (!body.messages || !Array.isArray(body.messages)) {
    return NextResponse.json({ error: 'Brak pola messages' }, { status: 400 })
  }

  try {
    const res = await fetch('https://api.deepseek.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${apiKey}`,
      },
      body: JSON.stringify({
        model: 'deepseek-chat',
        messages: body.messages,
        temperature: 0.7,
        max_tokens: 2048,
      }),
      signal: AbortSignal.timeout(30000),
    })

    if (!res.ok) {
      const errText = await res.text()
      return NextResponse.json(
        { error: `DeepSeek API: ${res.status} — ${errText.slice(0, 200)}` },
        { status: res.status }
      )
    }

    const data = await res.json()
    const content = data.choices?.[0]?.message?.content ?? ''
    return NextResponse.json({ content })
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : 'Nieznany błąd'
    return NextResponse.json({ error: `Błąd połączenia: ${msg}` }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import type { CoverResult } from '@/lib/music-types'

export const dynamic = 'error'

interface ITunesResponse {
  results?: Array<{ artworkUrl100?: string }>
}

interface MusicBrainzResponse {
  releases?: Array<{ id: string }>
}

export async function GET(req: NextRequest) {
  const safeUrl = req.url || 'http://localhost/api/cover-art'
  const { searchParams } = new URL(safeUrl)
  const artist = searchParams.get('artist') ?? ''
  const album = searchParams.get('album') ?? ''
  const title = searchParams.get('title') ?? ''

  if (!artist) {
    return NextResponse.json({ error: 'Brak parametru artist' }, { status: 400 })
  }

  const results: CoverResult[] = []

  // iTunes Search API — darmowe, bez klucza
  try {
    const query = encodeURIComponent(`${artist} ${album || title}`.trim())
    const res = await fetch(
      `https://itunes.apple.com/search?term=${query}&media=music&limit=6&entity=album`,
      { next: { revalidate: 3600 } }
    )
    if (res.ok) {
      const data = (await res.json()) as ITunesResponse
      for (const item of data.results ?? []) {
        if (item.artworkUrl100) {
          results.push({
            url: item.artworkUrl100.replace('100x100', '600x600'),
            source: 'iTunes',
            size: '600x600',
          })
        }
      }
    }
  } catch {}

  // MusicBrainz + Cover Art Archive — fallback
  if (results.length === 0) {
    try {
      const mbQuery = encodeURIComponent(`artist:"${artist}" AND release:"${album || title}"`)
      const mbRes = await fetch(
        `https://musicbrainz.org/ws/2/release/?query=${mbQuery}&limit=3&fmt=json`,
        { headers: { 'User-Agent': 'BONZO_media_HUB/1.0 (contact@example.com)' }, next: { revalidate: 3600 } }
      )
      if (mbRes.ok) {
        const mbData = (await mbRes.json()) as MusicBrainzResponse
        for (const release of mbData.releases ?? []) {
          results.push({
            url: `https://coverartarchive.org/release/${release.id}/front-500`,
            source: 'MusicBrainz',
            size: '500x500',
          })
        }
      }
    } catch {}
  }

  return NextResponse.json({ results })
}

